@page "/notifications"
@rendermode InteractiveServer
@using BlazorNotifications.Services
@inject NotificationService NotificationService
@implements IDisposable

<PageTitle>Notifications</PageTitle>

<h1>Notifications</h1>

<div class="mb-3">
    <span class="badge bg-primary fs-5">@_notifications.Count</span>
    <span class="ms-2">notification(s)</span>
</div>

@if (_notifications.Count == 0)
{
    <p><em>No notifications yet.</em></p>
}
else
{
    <ul class="list-group">
        @foreach (var notification in _notifications.OrderByDescending(n => n.Timestamp))
        {
            <li class="list-group-item d-flex justify-content-between align-items-start">
                <div>
                    <strong>#@notification.Id</strong> &mdash; @notification.Message
                </div>
                <small class="text-muted">@notification.Timestamp.ToString("HH:mm:ss")</small>
            </li>
        }
    </ul>
}

@code {
    private List<Notification> _notifications = new();
    private CancellationTokenSource? _cts;

    // Runs during both prerender and interactive render.
    // Loads initial data so it appears in the server-rendered HTML.
    protected override void OnInitialized()
    {
        _notifications = NotificationService.GetNotifications();
    }

    // Only runs once the component is fully interactive (not during prerender).
    // This is where we start the polling loop.
    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender)
        {
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken cancellationToken)
    {
        // Determine the highest ID we already have so we only fetch new ones.
        var lastId = _notifications.Count > 0 ? _notifications.Max(n => n.Id) : 0;

        while (!cancellationToken.IsCancellationRequested)
        {
            try
            {
                await Task.Delay(TimeSpan.FromSeconds(5), cancellationToken);

                // Simulate the service producing a new notification each poll cycle.
                NotificationService.SimulateNewNotification();

                var newer = NotificationService.GetNotificationsSince(lastId);
                if (newer.Count > 0)
                {
                    _notifications.AddRange(newer);
                    lastId = newer.Max(n => n.Id);
                    await InvokeAsync(StateHasChanged);
                }
            }
            catch (TaskCanceledException)
            {
                // Expected on disposal — exit cleanly.
                break;
            }
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

